export { SpotlightText } from "./SpotlightText";
export type {
  SpotlightTextProps,
  SpotlightTextTheme,
  SpotlightGlowColors,
} from "./types";

"use client";

import {
  useMemo,
  useEffect,
  type CSSProperties,
  type ReactNode,
} from "react";
import { cn } from "../../lib/utils";
import { useSpotlightCursor } from "./hooks/useSpotlightCursor";
import { SPOTLIGHT_THEMES } from "./themes";
import type { SpotlightTextProps } from "./types";

const DEFAULT_FONT_SIZE = "clamp(4rem, 15vw, 11.25rem)";
const BULB_CHARS = new Set(["i", "j"]);
const BULB_PROXIMITY = 80;

function resolveFontSize(fontSize: string | number | undefined): string {
  if (fontSize === undefined) return DEFAULT_FONT_SIZE;
  return typeof fontSize === "number" ? `${fontSize}px` : fontSize;
}

function bulbOpacityFromDistance(
  cursorX: number,
  cursorY: number,
  rect: DOMRect,
  containerRect: DOMRect,
  isHovered: boolean
): number {
  if (!isHovered) return 0;

  const centerX = rect.left - containerRect.left + rect.width / 2;
  const centerY = rect.top - containerRect.top + rect.height * 0.15;
  const dx = cursorX - centerX;
  const dy = cursorY - centerY;
  const distance = Math.sqrt(dx * dx + dy * dy);

  const base = 0.55;
  const peak = 1;
  if (distance >= BULB_PROXIMITY) return base;
  return base + (peak - base) * (1 - distance / BULB_PROXIMITY);
}

function renderCharacters(
  text: string,
  options: { showBulb: boolean; bulbColor: string; bulbBloom: string; isHovered: boolean }
): ReactNode[] {
  const { showBulb, bulbColor, bulbBloom, isHovered } = options;
  const chars: ReactNode[] = [];

  for (let index = 0; index < text.length; index++) {
    const char = text[index]!;

    if (showBulb && BULB_CHARS.has(char)) {
      chars.push(
        <span key={`${char}-${index}`} className="relative inline-block">
          {char}
          <span
            aria-hidden
            data-bulb=""
            className="pointer-events-none absolute left-1/2 rounded-full transition-[opacity] duration-200 ease-out"
            style={{
              top: "0.08em",
              width: "0.09em",
              height: "0.09em",
              minWidth: 12,
              minHeight: 12,
              transform: "translate(-50%, -50%)",
              background: bulbColor,
              boxShadow: bulbBloom,
              opacity: isHovered ? 0.75 : 0,
            }}
          />
        </span>
      );
    } else {
      chars.push(
        <span key={`${char}-${index}`} className="inline-block">
          {char}
        </span>
      );
    }
  }

  return chars;
}

export function SpotlightText({
  text,
  theme = "light",
  spotlightRadius = 120,
  fontSize,
  fontWeight = 800,
  letterSpacing = "-0.02em",
  showBulb = true,
  glowColors,
  as: Component = "span",
  className,
  style,
}: SpotlightTextProps) {
  const tokens = SPOTLIGHT_THEMES[theme];
  const resolvedFontSize = resolveFontSize(fontSize);

  const glowCore = glowColors?.core ?? tokens.glowCore;
  const glowMid = glowColors?.mid ?? tokens.glowMid;
  const bulbColor = glowColors?.bulb ?? tokens.bulb;

  const { containerRef, cursor, isHovered, reducedMotion, handlers } =
    useSpotlightCursor();

  const sharedTextStyle: CSSProperties = {
    fontSize: resolvedFontSize,
    fontWeight,
    letterSpacing,
    lineHeight: 1,
    fontFamily: "inherit",
    whiteSpace: "pre",
  };

  const containerStyle: CSSProperties = {
    background: tokens.surface,
    ...style,
  };

  const cssVars = {
    "--spotlight-x": `${cursor.x}px`,
    "--spotlight-y": `${cursor.y}px`,
    "--spotlight-radius": `${spotlightRadius}px`,
    "--glow-core": glowCore,
    "--glow-mid": glowMid,
  } as CSSProperties;

  const charOptions = useMemo(
    () => ({ showBulb, bulbColor, bulbBloom: tokens.bulbBloom, isHovered }),
    [showBulb, bulbColor, tokens.bulbBloom, isHovered]
  );

  const baseCharacters = useMemo(
    () => renderCharacters(text, charOptions),
    [text, charOptions]
  );

  const glowCharacters = useMemo(
    () => renderCharacters(text, { ...charOptions, showBulb: false }),
    [text, charOptions]
  );

  useEffect(() => {
    const container = containerRef.current;
    if (!container || !showBulb) return;

    const containerRect = container.getBoundingClientRect();
    const bulbs = container.querySelectorAll<HTMLElement>("[data-bulb]");

    bulbs.forEach((bulb) => {
      const wrapper = bulb.parentElement;
      if (!wrapper) return;
      const rect = wrapper.getBoundingClientRect();
      bulb.style.opacity = String(
        bulbOpacityFromDistance(
          cursor.x,
          cursor.y,
          rect,
          containerRect,
          isHovered
        )
      );
    });
  }, [containerRef, cursor.x, cursor.y, isHovered, showBulb]);

  const baseShadow = `${tokens.debossHighlight}, ${tokens.debossShadow}`;
  const activeShadow = `${tokens.activeHighlight}, ${tokens.activeShadow}`;

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative inline-flex items-center justify-center select-none px-8 py-10",
        className
      )}
      style={{ ...containerStyle, ...cssVars }}
      {...handlers}
    >
      <Component className="relative inline-block" style={sharedTextStyle}>
        {/* Base: debossed idle text */}
        <span
          className="relative z-[1] block"
          style={{
            ...sharedTextStyle,
            color: tokens.idleText,
            textShadow: baseShadow,
          }}
        >
          {baseCharacters}
        </span>

        {/* Glow: golden gradient clipped to glyphs only */}
        {!reducedMotion && (
          <span
            aria-hidden
            className="pointer-events-none absolute left-0 top-0 z-[2] block"
            style={{
              ...sharedTextStyle,
              color: "transparent",
              backgroundImage: isHovered
                ? `radial-gradient(circle var(--spotlight-radius) at var(--spotlight-x) var(--spotlight-y), var(--glow-core) 0%, var(--glow-mid) 40%, transparent 70%)`
                : "none",
              WebkitBackgroundClip: "text",
              backgroundClip: "text",
              textShadow: isHovered ? activeShadow : "none",
              opacity: isHovered ? 1 : 0,
              transition: "opacity 150ms ease",
            }}
          >
            {glowCharacters}
          </span>
        )}

        {/* Reduced motion: static warm tint */}
        {reducedMotion && (
          <span
            aria-hidden
            className="pointer-events-none absolute left-0 top-0 z-[2] block"
            style={{
              ...sharedTextStyle,
              color: "transparent",
              backgroundImage: `linear-gradient(135deg, ${glowCore}, ${glowMid})`,
              WebkitBackgroundClip: "text",
              backgroundClip: "text",
              opacity: 0.85,
            }}
          >
            {glowCharacters}
          </span>
        )}
      </Component>
    </div>
  );
}

import type { CSSProperties, ElementType } from "react";

export type SpotlightTextTheme = "light" | "dark";

export interface SpotlightGlowColors {
  core?: string;
  mid?: string;
  bulb?: string;
}

export interface SpotlightTextProps {
  /** Text to render */
  text: string;
  /** Surface and deboss palette */
  theme?: SpotlightTextTheme;
  /** Spotlight radius in px */
  spotlightRadius?: number;
  /** Display font size */
  fontSize?: string | number;
  fontWeight?: number;
  letterSpacing?: string;
  /** Glowing ascender-dot bulbs on i/j characters */
  showBulb?: boolean;
  /** Override theme glow colors */
  glowColors?: SpotlightGlowColors;
  /** Semantic HTML element */
  as?: ElementType;
  className?: string;
  style?: CSSProperties;
}

import type { SpotlightTextTheme } from "./types";

export interface SpotlightThemeTokens {
  surface: string;
  idleText: string;
  debossHighlight: string;
  debossShadow: string;
  glowCore: string;
  glowMid: string;
  bulb: string;
  bulbBloom: string;
  activeHighlight: string;
  activeShadow: string;
}

export const SPOTLIGHT_THEMES: Record<SpotlightTextTheme, SpotlightThemeTokens> = {
  light: {
    surface: "#eaeaea",
    idleText: "#b8b8b8",
    debossHighlight: "0 1px 0 rgba(255, 255, 255, 0.9)",
    debossShadow: "0 -1px 2px rgba(0, 0, 0, 0.15)",
    glowCore: "#d4c050",
    glowMid: "#c0a830",
    bulb: "#e8e85a",
    bulbBloom: "0 0 20px 10px rgba(232, 232, 90, 0.3), 0 0 40px 20px rgba(232, 232, 90, 0.1)",
    activeHighlight: "0 -1px 0 rgba(255, 255, 255, 0.4)",
    activeShadow: "0 2px 3px rgba(0, 0, 0, 0.2)",
  },
  dark: {
    surface: "#1a1a1a",
    idleText: "#454545",
    debossHighlight: "0 -1px 0 rgba(255, 255, 255, 0.06)",
    debossShadow: "0 2px 4px rgba(0, 0, 0, 0.6)",
    glowCore: "#e8c848",
    glowMid: "#c8a030",
    bulb: "#f0e868",
    bulbBloom: "0 0 24px 12px rgba(240, 232, 104, 0.35), 0 0 48px 24px rgba(240, 232, 104, 0.12)",
    activeHighlight: "0 1px 0 rgba(255, 255, 255, 0.15)",
    activeShadow: "0 -2px 3px rgba(0, 0, 0, 0.5)",
  },
};

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

interface CursorPosition {
  x: number;
  y: number;
}

interface UseSpotlightCursorOptions {
  disabled?: boolean;
}

export function useSpotlightCursor({ disabled = false }: UseSpotlightCursorOptions = {}) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isHovered, setIsHovered] = useState(false);
  const [cursor, setCursor] = useState<CursorPosition>({ x: -9999, y: -9999 });
  const [reducedMotion, setReducedMotion] = useState(false);

  useEffect(() => {
    const mql = window.matchMedia("(prefers-reduced-motion: reduce)");
    setReducedMotion(mql.matches);
    const handler = (event: MediaQueryListEvent) => setReducedMotion(event.matches);
    mql.addEventListener("change", handler);
    return () => mql.removeEventListener("change", handler);
  }, []);

  const updatePosition = useCallback((clientX: number, clientY: number) => {
    const el = containerRef.current;
    if (!el) return;

    const rect = el.getBoundingClientRect();
    setCursor({
      x: clientX - rect.left,
      y: clientY - rect.top,
    });
  }, []);

  const handleMouseMove = useCallback(
    (event: React.MouseEvent<HTMLDivElement>) => {
      if (disabled || reducedMotion) return;
      updatePosition(event.clientX, event.clientY);
    },
    [disabled, reducedMotion, updatePosition]
  );

  const handleTouchMove = useCallback(
    (event: React.TouchEvent<HTMLDivElement>) => {
      if (disabled || reducedMotion) return;
      const touch = event.touches[0];
      if (!touch) return;
      updatePosition(touch.clientX, touch.clientY);
    },
    [disabled, reducedMotion, updatePosition]
  );

  const handleTouchStart = useCallback(
    (event: React.TouchEvent<HTMLDivElement>) => {
      if (disabled || reducedMotion) return;
      const touch = event.touches[0];
      if (!touch) return;
      setIsHovered(true);
      updatePosition(touch.clientX, touch.clientY);
    },
    [disabled, reducedMotion, updatePosition]
  );

  const handleMouseEnter = useCallback(() => {
    setIsHovered(true);
  }, []);

  const handleMouseLeave = useCallback(() => {
    setIsHovered(false);
    setCursor({ x: -9999, y: -9999 });
  }, []);

  const handleTouchEnd = useCallback(() => {
    setIsHovered(false);
    setCursor({ x: -9999, y: -9999 });
  }, []);

  return {
    containerRef,
    cursor,
    isHovered,
    reducedMotion,
    handlers: {
      onMouseMove: handleMouseMove,
      onMouseEnter: handleMouseEnter,
      onMouseLeave: handleMouseLeave,
      onTouchMove: handleTouchMove,
      onTouchStart: handleTouchStart,
      onTouchEnd: handleTouchEnd,
    },
  };
}
